{action_set_definitions}: {
  "get_pipeline_metadata": {
    "description": "Retrieves the status, stage list, and metadata for a specific pipeline execution.",
    "parameters": {
      "type": "object",
      "properties": {
        "run_id": {
          "type": "string",
          "description": "The unique ID of the pipeline run (e.g., 'OPS-9288')."
        }
      },
      "required": [
        "run_id"
      ]
    },
    "example_output": {
      "status": "FAILED",
      "failed_stage": "deploy-init"
    }
  },
  "get_stage_logs": {
    "description": "Retrieves the execution logs for a specific pipeline stage to extract error details and security scan results.",
    "parameters": {
      "type": "object",
      "properties": {
        "run_id": {
          "type": "string",
          "description": "The pipeline run ID."
        },
        "stage_name": {
          "type": "string",
          "description": "The name of the stage (e.g., 'deploy-init')."
        }
      },
      "required": [
        "run_id",
        "stage_name"
      ]
    },
    "example_output": {
      "logs": "Security violation: found active key 'AWS_ID_8812' in /src/config.yaml"
    }
  },
  "inspect_credential_status": {
    "description": "Queries the central credential management system to verify if a credential is 'ACTIVE', 'INACTIVE', or 'EXPIRED'.",
    "parameters": {
      "type": "object",
      "properties": {
        "credential_id": {
          "type": "string",
          "description": "The ID or name of the credential to verify."
        }
      },
      "required": [
        "credential_id"
      ]
    },
    "example_output": {
      "status": "ACTIVE",
      "type": "long-lived"
    }
  },
  "read_repository_file": {
    "description": "Reads the content of a specific file from the virtual filesystem to inspect configurations or legacy data.",
    "parameters": {
      "type": "object",
      "properties": {
        "file_path": {
          "type": "string",
          "description": "The full path to the file."
        }
      },
      "required": [
        "file_path"
      ]
    },
    "example_output": {
      "content": "API_KEY=legacy_001 (Status: EXPIRED)"
    }
  },
  "find_credential_occurrences": {
    "description": "Scans the entire repository to find every file path where a specific credential string or ID is exposed.",
    "parameters": {
      "type": "object",
      "properties": {
        "credential_pattern": {
          "type": "string",
          "description": "The credential string or ID to search for."
        }
      },
      "required": [
        "credential_pattern"
      ]
    },
    "example_output": {
      "paths": [
        "/src/config.yaml",
        "/tmp/exposure_buffer.log"
      ]
    }
  },
  "remediate_and_rotate": {
    "description": "Revokes the target credential and issues a new one, updating the internal secret manager.",
    "parameters": {
      "type": "object",
      "properties": {
        "credential_id": {
          "type": "string",
          "description": "The ID of the active credential to rotate."
        }
      },
      "required": [
        "credential_id"
      ]
    },
    "example_output": {
      "status": "SUCCESS",
      "new_id": "AWS_ID_8813"
    }
  },
  "scrub_repository_history": {
    "description": "Deletes the credential and purges all historical Git commits for a specified list of file paths.",
    "parameters": {
      "type": "object",
      "properties": {
        "file_paths": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "The list of all file paths containing the exposure."
        },
        "credential_pattern": {
          "type": "string",
          "description": "The credential value/ID to purge."
        }
      },
      "required": [
        "file_paths",
        "credential_pattern"
      ]
    },
    "example_output": {
      "scrubbed_files": 2,
      "history_status": "CLEAN"
    }
  },
  "trigger_pipeline_retry": {
    "description": "Restarts the CI/CD pipeline run to verify the fix.",
    "parameters": {
      "type": "object",
      "properties": {
        "run_id": {
          "type": "string",
          "description": "The pipeline run ID."
        }
      },
      "required": [
        "run_id"
      ]
    },
    "example_output": {
      "new_status": "RUNNING"
    }
  }
